INSERT INTO `frontends` VALUES (1,'seo.data','{\"seo_image\":\"1\",\"keywords\":[\"investment\",\"crownmaire\",\"crown maire\",\"investment firm\",\"hedge funds\"],\"description\":\"Crownmaire Capital provides the best investment opportunities with high returns.\",\"social_title\":\"Crownmaire- Best Investment Firm\",\"social_description\":\"Crownmaire Capital is the investment platform where you can invest and can get the high returns.\",\"image\":\"67be891af14c51740540186.png\"}','global','2020-07-04 23:42:52','2025-02-25 22:23:07'),(41,'cookie.data','{\"short_desc\":\"We may use cookies or any other tracking technologies when you visit our website, including any other media form, mobile website, or mobile application related or connected to help customize the Site and improve your experience.\",\"description\":\"<div class=\\\"mb-5\\\">\\r\\n    <h3 class=\\\"mb-3\\\">\\r\\n        What information do we collect?<\\/h3>\\r\\n    <p class=\\\"font-18\\\">We gather data from you\\r\\n        when you register on our site, submit a request, buy any services, react to an overview, or round out a\\r\\n        structure. At the point when requesting any assistance or enrolling on our site, as suitable, you might be\\r\\n        approached to enter your: name, email address, or telephone number. You may, nonetheless, visit our site\\r\\n        anonymously.<\\/p>\\r\\n<\\/div>\\r\\n<div class=\\\"mb-5\\\">\\r\\n    <h3 class=\\\"mb-3\\\">\\r\\n        How do we protect your information?<\\/h3>\\r\\n    <p class=\\\"font-18\\\">All provided\\r\\n        delicate\\/credit data is sent through Stripe.<br>After an exchange, your private data (credit cards, social\\r\\n        security numbers, financials, and so on) won\'t be put away on our workers.<\\/p>\\r\\n<\\/div>\\r\\n<div class=\\\"mb-5\\\">\\r\\n    <h3 class=\\\"mb-3\\\">\\r\\n        Do we disclose any information to outside parties?<\\/h3>\\r\\n    <p class=\\\"font-18\\\">We don\'t sell, exchange,\\r\\n        or in any case move to outside gatherings by and by recognizable data. This does exclude confided in outsiders\\r\\n        who help us in working our site, leading our business, or adjusting you, since those gatherings consent to keep\\r\\n        this data private. We may likewise deliver your data when we accept discharge is suitable to follow the law,\\r\\n        implement our site strategies, or ensure our own or others\' rights, property, or wellbeing.<\\/p>\\r\\n<\\/div>\\r\\n<div class=\\\"mb-5\\\">\\r\\n    <h3 class=\\\"mb-3\\\">\\r\\n        Children\'s Online Privacy Protection Act Compliance<\\/h3>\\r\\n    <p class=\\\"font-18\\\">We are consistent with\\r\\n        the prerequisites of COPPA (Children\'s Online Privacy Protection Act), we don\'t gather any data from anybody\\r\\n        under 13 years old. Our site, items, and administrations are completely coordinated to individuals who are in\\r\\n        any event 13 years of age or more established.<\\/p>\\r\\n<\\/div>\\r\\n<div class=\\\"mb-5\\\">\\r\\n    <h3 class=\\\"mb-3\\\">\\r\\n        Changes to our Privacy Policy<\\/h3>\\r\\n    <p class=\\\"font-18\\\">If we decide to change\\r\\n        our privacy policy, we will post those changes on this page.<\\/p>\\r\\n<\\/div>\\r\\n<div class=\\\"mb-5\\\">\\r\\n    <h3 class=\\\"mb-3\\\">\\r\\n        How long we retain your information?<\\/h3>\\r\\n    <p class=\\\"font-18\\\">At the point when you\\r\\n        register for our site, we cycle and keep your information we have about you however long you don\'t erase the\\r\\n        record or withdraw yourself (subject to laws and guidelines).<\\/p>\\r\\n<\\/div>\\r\\n<div class=\\\"mb-5\\\">\\r\\n    <h3 class=\\\"mb-3\\\">\\r\\n        What we don\\u2019t do with your data<\\/h3>\\r\\n    <p class=\\\"font-18\\\">We don\'t and will never\\r\\n        share, unveil, sell, or in any case give your information to different organizations for the promoting of their\\r\\n        items or administrations.<\\/p>\\r\\n<\\/div>\",\"status\":1}','global','2020-07-04 23:42:52','2022-09-24 01:10:22'),(44,'maintenance.data','{\"description\":\"<div class=\\\"text-center\\\"><h3 class=\\\"mb-3\\\"><p data-start=\\\"73\\\" data-end=\\\"101\\\"><strong data-start=\\\"73\\\" data-end=\\\"101\\\"><font size=\\\"5\\\">Portal Under Maintenance<\\/font><\\/strong><\\/p><p data-start=\\\"73\\\" data-end=\\\"101\\\"><strong data-start=\\\"73\\\" data-end=\\\"101\\\"><font size=\\\"5\\\"><br><\\/font><\\/strong><\\/p><p data-start=\\\"103\\\" data-end=\\\"196\\\"><font size=\\\"3\\\" face=\\\"arial\\\">We are currently performing scheduled maintenance on our portal to improve your experience.<\\/font><\\/p><p data-start=\\\"198\\\" data-end=\\\"332\\\"><font size=\\\"3\\\" face=\\\"arial\\\">If you have any questions or need assistance, please feel free to contact us at&nbsp;<b>+1 (917) 500 6476<\\/b>&nbsp;or email us at <strong data-start=\\\"308\\\" data-end=\\\"331\\\" style=\\\"\\\"><a data-start=\\\"310\\\" data-end=\\\"329\\\" class=\\\"cursor-pointer\\\" rel=\\\"noopener\\\">info@crownmaire.com<\\/a><\\/strong>.<\\/font><\\/p><p data-start=\\\"334\\\" data-end=\\\"398\\\"><font size=\\\"3\\\" face=\\\"arial\\\">We apologize for the inconvenience and appreciate your patience.<\\/font><\\/p><p data-start=\\\"73\\\" data-end=\\\"101\\\"><strong data-start=\\\"73\\\" data-end=\\\"101\\\">\\r\\n\\r\\n\\r\\n<\\/strong><\\/p><p data-start=\\\"400\\\" data-end=\\\"417\\\"><b><font size=\\\"2\\\">\\u2014 Team Crownmaire<\\/font><\\/b><\\/p>\\r\\n<p data-start=\\\"103\\\" data-end=\\\"196\\\"><\\/p><\\/h3><\\/div>\"}','global','2020-07-04 23:42:52','2025-06-23 12:14:06'),(206,'about.content','{\"has_image\":\"1\",\"heading_w\":\"About\",\"heading_c\":\"Us\",\"button_name\":\"More Info\",\"button_link\":\"about\",\"content\":\"AWSVision is an international investment financial company trading on the S&amp;P 500 exchange by professional traders. Our goal is to provide our investors with a reliable source of income, while minimizing investment risks. \\n\\nAWSVision automates the relation between the investor and the trustee. Our efforts are focused on increasing your profit margin by making sound investments that yield continuous profits to our investors. We look forward to you joining us and becoming part of a proven and tested wealth-building system\",\"image\":\"631d85749f9311662879092.jpg\"}','bit_gold','2022-09-10 12:26:58','2024-07-31 21:39:07'),(207,'banner.content','{\"has_image\":\"1\",\"heading_w\":\"Welcome To AWSVISION,\",\"heading_c\":\"where you can invest in a stable platform and get higher than normal returns. Ask us how.\",\"sub_heading\":\"Invest in an industry leader, professional, and reliable company. We provide you with the most reliable features that will make your experience better. Not only do we guarantee the highest returns on your investments, but we also guarantee your investment will be totally secured.\",\"button_name\":\"Sign Up\",\"button_link\":\"user\\/register\",\"image\":\"631c9810cbce71662818320.jpg\"}','bit_gold','2022-09-10 12:28:40','2024-09-13 01:22:07'),(208,'blog.content','{\"heading\":\"Our Latest News\",\"sub_heading\":\"you will get each update about our system and the world market in this area. Keep checking our Latest News to be in touch.\"}','bit_gold','2022-09-10 12:28:58','2022-09-10 12:28:58'),(210,'blog.content','{\"heading\":\"Our Latest News\",\"sub_heading\":\"you will get each update about our system and the world market in this area. Keep checking our Latest News to be in touch.\"}','neo_dark','2022-09-10 12:30:04','2022-09-10 12:32:20'),(216,'about.content','{\"has_image\":\"1\",\"heading\":\"About AWSVision\",\"content\":\"Welcome to AWSVision, your gateway to a world of intelligent investments. At AWSVision, we specialize in empowering individuals to harness the potential of the financial markets, specifically in gold, silver, oil, and prominent US companies. Our mission is to provide a seamless platform for investors to grow their wealth and achieve financial prosperity.\\n\\nAWSVision offers carefully crafted investment plans that allow individuals to participate in the lucrative markets of gold, silver, oil, and leading US companies. We understand the importance of diversification and tailor our plans to optimize returns while managing risk effectively.\",\"image\":\"631d8591816a01662879121.png\"}','neo_dark','2022-09-10 12:41:00','2024-03-06 09:20:50'),(217,'banner.content','{\"has_image\":\"1\",\"heading\":\"Invest for Future in Stable Platform and Make Fast Money\",\"button_name\":\"Sign Up\",\"button_link\":\"user\\/register\",\"button_two_name\":\"Sign In\",\"button_two_link\":\"user\\/login\",\"sub_heading\":\"AWSVision - Navigating Wealth, Unleashing Potential: Your Monthly Gateway to Intelligent Investments in Gold, Silver, Oil, and US Companies.\",\"image\":\"631d8664f2ab11662879332.png\"}','neo_dark','2022-09-10 12:52:54','2024-03-06 09:22:45'),(218,'calculation.content','{\"heading_w\":\"Profit\",\"heading_c\":\"Calculator\",\"sub_heading\":\"You must know the calculation before investing in any plan, so you never make mistakes. Check the calculation and you will get as our calculator says.\"}','bit_gold','2022-09-10 12:54:00','2022-09-10 12:54:00'),(219,'calculation.content','{\"has_image\":\"1\",\"heading\":\"Profit Calculator\",\"sub_heading\":\"You must know the calculation before investing in any plan, so you never make mistakes. Check the calculation and you will get as our calculator says.\",\"image\":\"633ef22566efe1665069605.png\"}','neo_dark','2022-09-10 12:54:11','2022-10-06 09:20:05'),(220,'contact.content','{\"has_image\":\"1\",\"heading\":\"Contact With Us\",\"sub_heading\":\"If you have any questions or queries that are not answered on our website, please feel free to contact us. We will try to respond to you as soon as possible. Thank you so much.\",\"image\":\"631c9e4f1666c1662819919.jpg\"}','bit_gold','2022-09-10 12:55:19','2022-09-10 12:55:19'),(221,'contact.element','{\"icon\":\"<i class=\\\"las la-phone\\\"><\\/i>\",\"title\":\"Phone Number\",\"content\":\"+1 (469) 754 2201\"}','bit_gold','2022-09-10 12:55:45','2024-09-25 23:32:21'),(222,'contact.element','{\"icon\":\"<i class=\\\"far fa-envelope-open\\\"><\\/i>\",\"title\":\"Email Address\",\"content\":\"info@awsvision.com\"}','bit_gold','2022-09-10 12:56:00','2024-07-12 22:35:22'),(224,'contact.content','{\"title\":null,\"subtitle\":null}','invester','2022-09-10 12:57:59','2022-09-10 12:57:59'),(225,'contact.element','{\"icon\":\"<i class=\\\"las la-phone\\\"><\\/i>\",\"title\":\"Phone Number\",\"content\":\"+1 (469)-754-2201\"}','invester','2022-09-10 12:57:59','2024-10-24 23:00:19'),(226,'contact.element','{\"icon\":\"<i class=\\\"far fa-envelope-open\\\"><\\/i>\",\"title\":\"Email Address\",\"content\":\"info@awsvision.com\"}','invester','2022-09-10 12:57:59','2024-10-22 23:43:11'),(227,'contact.element','{\"icon\":\"<i class=\\\"las la-map-marker\\\"><\\/i>\",\"title\":\"Office Address\",\"content\":\"11133 Shady Trail PMB 214 Dallas, TX\\u00a075229\"}','invester','2022-09-10 12:57:59','2024-10-22 23:44:02'),(228,'cta.content','{\"has_image\":\"1\",\"heading\":\"Get Started Today With Us\",\"sub_heading\":\"This is a sound low risk investment that pays our investors a higher profit, which they deserve. Our proven model guarantees our investors the fastest return on their investment, while maintaining the security of their portfolio packet.\",\"button_name\":\"Join Us\",\"button_url\":\"user\\/register\",\"image\":\"631c9f3d446e11662820157.jpg\"}','bit_gold','2022-09-10 12:59:17','2024-09-06 13:25:52'),(229,'faq.content','{\"heading_w\":\"Frequently Asked\",\"heading_c\":\"Questions\",\"sub_heading\":\"We answer some of your Frequently Asked Questions regarding our platform. If you have a query that is not answered here, Please contact us.\"}','bit_gold','2022-09-10 13:00:01','2022-09-10 13:00:01'),(230,'faq.element